<?php
if(!function_exists('rupiah')){function rupiah(float $a):string{if($a<0)return'-Rp '.number_format(abs($a),0,',','.');return'Rp '.number_format($a,0,',','.') ;}}
if(!function_exists('sanitize_month')){function sanitize_month(?string $m):string{$m=(int)($m??date('m'));if($m<1||$m>12)$m=(int)date('m');return str_pad($m,2,'0',STR_PAD_LEFT);}}
if(!function_exists('sanitize_year')){function sanitize_year(?string $y):string{$y=(int)($y??date('Y'));if($y<2000||$y>2100)$y=(int)date('Y');return(string)$y;}}
if(!function_exists('time_elapsed_string')){function time_elapsed_string(string $dt):string{try{$s=(new \DateTime())->getTimestamp()-(new \DateTime($dt))->getTimestamp();if($s<60)return'Baru saja';if($s<3600)return floor($s/60).' menit lalu';$h=floor($s/3600);if($h<24)return $h.' jam lalu';$d=floor($s/86400);if($d<7)return $d.' hari lalu';if($d<30)return floor($d/7).' minggu lalu';if($d<365)return floor($d/30).' bulan lalu';return floor($d/365).' tahun lalu';}catch(\Exception $e){return'Baru saja';}}}
if(!function_exists('short_number')){function short_number(float $n):string{if($n>=1000000000)return'Rp '.round($n/1000000000,1).'M';if($n>=1000000)return'Rp '.round($n/1000000,1).'jt';if($n>=1000)return'Rp '.round($n/1000,0).'rb';return rupiah($n);}}
if(!function_exists('percent_change')){function percent_change(float $old,float $new):?float{if($old==0)return null;return round((($new-$old)/abs($old))*100,1);}}
if(!function_exists('change_badge')){function change_badge(?float $c,bool $inv=false):string{if($c===null)return'<span class="badge bg-secondary">—</span>';if($c>0){$color=$inv?'danger':'success';return'<span class="badge bg-'.$color.'"><i class="bi bi-arrow-up-short"></i>'.$c.'%</span>';}if($c<0){$color=$inv?'success':'danger';return'<span class="badge bg-'.$color.'"><i class="bi bi-arrow-down-short"></i>'.abs($c).'%</span>';}return'<span class="badge bg-secondary">0%</span>';}}